import { useEffect, useState } from "react";
import api from "../services/api";
import toast from "react-hot-toast";

export default function Admin() {
  const [items, setItems] = useState([]);
  const [claims, setClaims] = useState([]);
  const [loading, setLoading] = useState(true);

  /* ================= LOAD DATA ================= */

  const loadData = async () => {
    try {
      setLoading(true);

      const [itemsRes, claimsRes] = await Promise.all([
        api.get("/items"),
        api.get("/items/admin/claims")
      ]);

      setItems(itemsRes.data);
      setClaims(claimsRes.data);

    } catch (err) {
      console.error("ADMIN LOAD ERROR:", err);
      toast.error("Failed to load admin data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  /* ================= ITEM ACTIONS ================= */

  const approveItem = async (id) => {
    try {
      await api.put(`/items/${id}/approve`);
      toast.success("Item approved");
      loadData();
    } catch (err) {
      toast.error("Failed to approve item");
    }
  };

  const deleteItem = async (id) => {
    if (!window.confirm("Delete this item permanently?")) return;

    try {
      await api.delete(`/items/${id}`);
      toast.success("Item deleted");
      loadData();
    } catch (err) {
      toast.error("Delete failed");
    }
  };

  /* ================= CLAIM ACTIONS ================= */

  const approveClaim = async (itemId, claimId) => {
    try {
      await api.put(`/items/${itemId}/claims/${claimId}/approve`);
      toast.success("Claim approved");
      loadData();
    } catch (err) {
      toast.error("Failed to approve claim");
    }
  };

  const rejectClaim = async (itemId, claimId) => {
    try {
      await api.put(`/items/${itemId}/claims/${claimId}/reject`);
      toast.success("Claim rejected");
      loadData();
    } catch (err) {
      toast.error("Failed to reject claim");
    }
  };

  /* ================= LOADING ================= */

  if (loading) {
    return (
      <div className="p-8 text-lg font-semibold">
        Loading admin dashboard...
      </div>
    );
  }

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-12">

      <h1 className="text-4xl font-extrabold">
        Admin Dashboard
      </h1>

      {/* ================= ITEMS ================= */}

      <section>
        <h2 className="text-2xl font-bold mb-4">
          Item Moderation
        </h2>

        {items.length === 0 ? (
          <p className="text-gray-500">No items found.</p>
        ) : (
          <div className="space-y-3">
            {items.map((item) => (
              <div
                key={item._id}
                className="bg-white p-4 rounded-xl shadow flex justify-between items-center"
              >
                <div>
                  <h3 className="font-bold">{item.title}</h3>
                  <p className="text-sm text-gray-500">
                    {item.type.toUpperCase()} • {item.status.toUpperCase()}
                  </p>
                </div>

                <div className="flex gap-2">
                  {item.status === "pending" && (
                    <button
                      onClick={() => approveItem(item._id)}
                      className="px-3 py-1 bg-green-600 text-white rounded"
                    >
                      Approve
                    </button>
                  )}

                  <button
                    onClick={() => deleteItem(item._id)}
                    className="px-3 py-1 bg-red-600 text-white rounded"
                  >
                    Delete
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      {/* ================= CLAIM REVIEW ================= */}

      <section>
        <h2 className="text-2xl font-bold mb-4">
          AI Claim Review
        </h2>

        {claims.length === 0 ? (
          <p className="text-gray-500">
            No claim requests yet.
          </p>
        ) : (
          <div className="space-y-6">
            {claims.map((item) => (
              <div
                key={item._id}
                className="bg-white p-4 rounded-xl shadow"
              >
                <h3 className="font-bold text-lg">
                  {item.title}
                </h3>

                {item.claims.map((claim, index) => {

                  const confidence =
                    claim.confidence || 0;

                  const confidenceColor =
                    confidence >= 80
                      ? "text-green-600"
                      : confidence >= 50
                      ? "text-yellow-600"
                      : "text-red-600";

                  return (
                    <div
                      key={index}
                      className="border rounded p-4 mt-4 bg-gray-50"
                    >
                      <p className="font-semibold">
                        {claim.userId?.name} ({claim.userId?.email})
                      </p>

                      <p className={`font-bold mt-1 ${confidenceColor}`}>
                        AI Confidence: {confidence}%
                      </p>

                      <ul className="list-disc ml-5 mt-2 text-sm">
                        {claim.answers.map((ans, i) => (
                          <li key={i}>{ans}</li>
                        ))}
                      </ul>

                      {claim.status === "pending" ? (
                        <div className="flex gap-3 mt-3">

                          <button
                            onClick={() =>
                              approveClaim(item._id, claim._id)
                            }
                            className="bg-green-600 text-white px-3 py-1 rounded"
                          >
                            Approve
                          </button>

                          <button
                            onClick={() =>
                              rejectClaim(item._id, claim._id)
                            }
                            className="bg-red-600 text-white px-3 py-1 rounded"
                          >
                            Reject
                          </button>

                        </div>
                      ) : (
                        <p className="mt-2 text-sm text-gray-500">
                          Status: {claim.status.toUpperCase()}
                        </p>
                      )}

                    </div>
                  );
                })}
              </div>
            ))}
          </div>
        )}
      </section>

    </div>
  );
}
